const email = $input.first().json;

// Limpiar angle-brackets de message IDs
const cleanId = (id) => (id || '').replace(/[<>\s]/g, '');

const rawMessageId = email.messageId
  || (email.headers && (email.headers['message-id'] || email.headers['Message-ID']))
  || email.id
  || '';

const rawInReplyTo = email.inReplyTo
  || (email.headers && (email.headers['in-reply-to'] || email.headers['In-Reply-To']))
  || '';

const rawReferences = email.references
  || (email.headers && (email.headers['references'] || email.headers['References']))
  || '';

const messageId = cleanId(rawMessageId) || (email.id || '');
const inReplyTo = cleanId(rawInReplyTo);
const threadId = email.threadId || inReplyTo || messageId;

// Extraer lista de referencias
const referencesList = rawReferences
  ? rawReferences.split(/\s+/).map(r => cleanId(r)).filter(Boolean)
  : [];

// from puede ser string o objeto
const fromObj = email.from || {};
const fromEmail = (fromObj.value && fromObj.value[0] && fromObj.value[0].address)
  || (typeof fromObj === 'string' ? fromObj : '')
  || '';
const fromName = (fromObj.value && fromObj.value[0] && fromObj.value[0].name) || fromEmail;

// to puede ser array u objeto
const toObj = email.to || {};
const toEmail = (toObj.value && toObj.value[0] && toObj.value[0].address)
  || (Array.isArray(toObj) ? toObj[0] : '')
  || '';

const attachmentsCount = (email.attachments || []).length;

return [{
  json: {
    ...email,
    _parsed: {
      messageId,
      inReplyTo,
      threadId,
      references: referencesList,
      fromEmail,
      fromName,
      toEmail,
      subject: email.subject || '',
      bodyText: email.text || '',
      bodyHtml: email.html || '',
      receivedAt: email.date || new Date().toISOString(),
      hasAttachments: attachmentsCount > 0,
      attachmentCount: attachmentsCount
    }
  }
}];

const resp = $input.first().json;
const parsed = $('Extraer Headers Email').first().json._parsed;

const statusCode = resp.statusCode || 200;
const body = resp.body || resp;

// Detectar error HTTP
const isHttpError = statusCode >= 400;
const errorMsg = isHttpError ? (body.detail || body.error || body.message || `HTTP ${statusCode}`) : null;

// Extraer campos de la respuesta del endpoint
// El endpoint devuelve: { tramite_id, strategy, requiere_accion, hilo_id, ... }
const tramiteId = body.tramite_id || null;
const strategy = body.strategy || null;  // 'reply_to_known', 'new_email', 'manual_queue', etc.
const requiereAccion = body.requiere_accion === true;
const hiloId = body.hilo_id || null;
const message = body.message || '';

// Determinar si es un reply a tramite conocido:
// tramite_id != null Y strategy != 'new_email' => hilo conocido
const esHiloConocido = (tramiteId !== null) && (strategy !== 'new_email') && (strategy !== null);

// Es email nuevo si strategy == 'new_email' o no hay tramite_id
const esEmailNuevo = (strategy === 'new_email') || (tramiteId === null && !isHttpError);

// Es manual_queue si strategy == 'manual_queue'
const esManualQueue = strategy === 'manual_queue';

console.log(`email/ingest: status=${statusCode}, strategy=${strategy}, tramite_id=${tramiteId}, requiere_accion=${requiereAccion}`);

return [{
  json: {
    // Datos del email originales
    ...parsed,
    // Resultado del ingest
    ingest_status_code: statusCode,
    ingest_error: errorMsg,
    ingest_ok: !isHttpError,
    tramite_id: tramiteId,
    strategy,
    requiere_accion: requiereAccion,
    hilo_id: hiloId,
    ingest_message: message,
    // Flags de decisión
    es_hilo_conocido: esHiloConocido,
    es_email_nuevo: esEmailNuevo,
    es_manual_queue: esManualQueue
  }
}];

