const ingestData = $('Evaluar Respuesta Ingest').first().json;
const email = $('Gmail Trigger').first().json;

// Extraer tramite_id del registro creado en Supabase
const supaResp = $input.first().json;
const supaBody = supaResp.body || supaResp;
const supaRecord = Array.isArray(supaBody) ? supaBody[0] : supaBody;
const tramitePipelineId = supaRecord?.id || ingestData.tramite_id || null;

// Obtener binarios de Gmail (adjuntos)
let gmailBinary = {};
try { gmailBinary = $('Gmail Trigger').first().binary || {}; } catch(e) { gmailBinary = {}; }

const adjuntos = [];
for (const [key, binaryInfo] of Object.entries(gmailBinary)) {
  if (binaryInfo && key.startsWith('attachment_')) {
    let base64Data = '';
    try {
      base64Data = Buffer.isBuffer(binaryInfo.data)
        ? binaryInfo.data.toString('base64')
        : (typeof binaryInfo.data === 'string' ? binaryInfo.data : '');
    } catch(e) { base64Data = ''; }
    adjuntos.push({
      campo: key,
      nombre_archivo: binaryInfo.fileName || key,
      tipo_mime: binaryInfo.mimeType || 'application/octet-stream',
      tamano_bytes: binaryInfo.fileSize || 0,
      datos_base64: base64Data
    });
  }
}

const emailData = {
  tramite_id: tramitePipelineId,
  remitente: ingestData.fromEmail,
  nombre_remitente: ingestData.fromName,
  asunto: ingestData.subject,
  cuerpo: ingestData.bodyText || '',
  cuerpo_html: ingestData.bodyHtml || '',
  fecha: ingestData.receivedAt,
  message_id: ingestData.messageId,
  thread_id: ingestData.threadId || email.threadId || '',
  tiene_adjuntos: adjuntos.length > 0,
  adjuntos_count: adjuntos.length,
  adjuntos
};

return [{
  json: {
    tramite_pipeline_id: tramitePipelineId,
    email_data: JSON.stringify(emailData),
    _adjuntos_count: adjuntos.length,
    // Pasar datos del email para uso posterior
    fromEmail: ingestData.fromEmail,
    fromName: ingestData.fromName,
    subject: ingestData.subject,
    bodyText: ingestData.bodyText
  }
}];

