const tramiteCreado = !errorDetectado && (body.twenty_tramite_id || body.tramite_created === true || body.folio);
const requiereRevision = body.requiere_revision === true || body.strategy === 'revision_manual' || (!tramiteCreado && !errorDetectado);

const folioGnp = body.folio || body.folio_gnp || null;
const twentyId = body.twenty_tramite_id || null;

console.log(`asignacion: status=${statusCode}, tramite_creado=${tramiteCreado}, folio=${folioGnp}, twenty_id=${twentyId}`);

return [{
  json: {
    tramite_pipeline_id: a1data.tramite_pipeline_id,
    fromEmail: a1data.fromEmail,
    fromName: a1data.fromName,
    subject: a1data.subject,
    ramo: a1data.ramo,
    tipo_tramite: a1data.tipo_tramite,
    error_detectado: errorDetectado,
    tramite_creado: tramiteCreado,
    requiere_revision: requiereRevision,
    folio: folioGnp,
    twenty_tramite_id: twentyId,
    asignacion_status: statusCode
  }
}];

